import json
import math
import re
from collections import defaultdict

# Load the clinical and expression data directly from the stored variables
# First, let's see what we have available
all_vars = {k: v for k, v in locals().items() if k.startswith('var_')}
print("Available variables:", list(all_vars.keys()))

# Try each variable and see what they contain
for var_name in all_vars:
    value = all_vars[var_name]
    print(f"\n{var_name}:")
    print(f"  Type: {type(value)}")
    print(f"  Length: {len(str(value)) if value else 0}")
    if isinstance(value, str):
        if len(value) < 500:
            print(f"  Content: {repr(value)}")
        else:
            print(f"  Content (first 300 chars): {repr(value[:300])}")
    elif isinstance(value, list) and len(value) > 0:
        print(f"  First record: {repr(value[0])}")
    else:
        print(f"  Content: {str(value)[:300]}")

